import React, { useState } from "react";

export default function ClaimAuditApp() {
  const [claimId, setClaimId] = useState("");
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);

  // Risk Level Helper
  const riskLevel = (score) => {
    if (score <= 40) return "Low Risk";
    if (score <= 75) return "Medium Risk";
    return "High Risk";
  };

  // Simulated API Call (Replace with real backend later)
  const analyzeClaim = async () => {
    if (!claimId) return alert("Enter Claim ID first");

    setLoading(true);

    setTimeout(() => {
      const mockResult = {
        total_estimate_pkr: 185000,
        fraud_confidence_score: 62,
        verdict: "Manual review recommended",
        damaged_parts: ["Front Bumper", "Left Headlight", "Hood"],
        fraud_analysis:
          "Multiple previous claims detected. Damage pattern partially inconsistent.",
        itemized_costs: {
          "Front Bumper": 60000,
          "Left Headlight": 45000,
          Hood: 80000,
        },
      };

      setResult(mockResult);
      setLoading(false);
    }, 1500);
  };

  // Professional HTML Report Download
  const downloadReport = () => {
    if (!result) return;

    const reportHTML = `
    <html>
      <head>
        <title>ClaimPilot AI Audit Report</title>
        <style>
          body {
            font-family: Arial, sans-serif;
            padding: 40px;
            background: #f9fafb;
            color: #111;
          }
          h1 { color: #1e40af; }
          .card {
            background: #ffffff;
            padding: 20px;
            border-radius: 12px;
            margin-bottom: 20px;
            box-shadow: 0 4px 10px rgba(0,0,0,0.05);
          }
          .risk-low { color: #16a34a; font-weight: bold; }
          .risk-medium { color: #f59e0b; font-weight: bold; }
          .risk-high { color: #dc2626; font-weight: bold; }
          ul { padding-left: 20px; }
          .footer {
            margin-top: 40px;
            font-size: 12px;
            color: #666;
          }
        </style>
      </head>
      <body>

        <h1>ClaimPilot AI - Damage Audit Report</h1>
        <p><strong>Claim ID:</strong> ${claimId}</p>
        <p><strong>Date:</strong> ${new Date().toLocaleString()}</p>

        <div class="card">
          <h2>Total Estimate</h2>
          <p><strong>PKR ${result.total_estimate_pkr}</strong></p>
        </div>

        <div class="card">
          <h2>Fraud Score</h2>
          <p class="${
            result.fraud_confidence_score <= 40
              ? "risk-low"
              : result.fraud_confidence_score <= 75
              ? "risk-medium"
              : "risk-high"
          }">
            ${result.fraud_confidence_score}% (${riskLevel(
      result.fraud_confidence_score
    )})
          </p>
        </div>

        <div class="card">
          <h2>Verdict</h2>
          <p><strong>${result.verdict}</strong></p>
        </div>

        <div class="card">
          <h2>Damaged Parts</h2>
          ${
            result.damaged_parts?.length
              ? `<ul>${result.damaged_parts
                  .map((part) => `<li>${part}</li>`)
                  .join("")}</ul>`
              : "<p>No parts detected.</p>"
          }
        </div>

        <div class="card">
          <h2>Fraud Analysis</h2>
          <p>${result.fraud_analysis || "No fraud detected."}</p>
        </div>

        <div class="card">
          <h2>Itemized Costs</h2>
          <pre>${JSON.stringify(result.itemized_costs, null, 2)}</pre>
        </div>

        <div class="footer">
          Generated by ClaimPilot AI System
        </div>

      </body>
    </html>
    `;

    const blob = new Blob([reportHTML], { type: "text/html" });
    const url = URL.createObjectURL(blob);

    const a = document.createElement("a");
    a.href = url;
    a.download = `ClaimPilot_Report_${claimId}.html`;
    a.click();

    URL.revokeObjectURL(url);
  };

  return (
    <div style={{ padding: "40px", fontFamily: "Arial" }}>
      <h1>🚗 ClaimPilot AI - Damage Claim Auditor</h1>

      <input
        type="text"
        placeholder="Enter Claim ID"
        value={claimId}
        onChange={(e) => setClaimId(e.target.value)}
        style={{
          padding: "10px",
          width: "250px",
          marginRight: "10px",
          borderRadius: "6px",
          border: "1px solid #ccc",
        }}
      />

      <button
        onClick={analyzeClaim}
        style={{
          padding: "10px 20px",
          backgroundColor: "#2563eb",
          color: "white",
          border: "none",
          borderRadius: "6px",
          cursor: "pointer",
        }}
      >
        {loading ? "Analyzing..." : "Analyze Claim"}
      </button>

      {result && (
        <div style={{ marginTop: "30px" }}>
          <h2>Analysis Complete</h2>
          <p>
            <strong>Total Estimate:</strong> PKR {result.total_estimate_pkr}
          </p>
          <p>
            <strong>Fraud Score:</strong> {result.fraud_confidence_score}% (
            {riskLevel(result.fraud_confidence_score)})
          </p>
          <p>
            <strong>Verdict:</strong> {result.verdict}
          </p>

          <button
            onClick={downloadReport}
            style={{
              marginTop: "20px",
              padding: "10px 20px",
              backgroundColor: "#16a34a",
              color: "white",
              border: "none",
              borderRadius: "6px",
              cursor: "pointer",
            }}
          >
            Download Full Report
          </button>
        </div>
      )}
    </div>
  );
}
